#include<bits/stdc++.h>
using namespace std;
int n,k,f[10001];
int a[10001];
int main()
{
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    f[1]=a[1];
    for(int i=1;i<=n;i++)
    {
        int max1=a[i];
        for(int j=i-1;j>=max(0,i-k);j--)
        {
            f[i]=max(f[i],f[j]+(i-j)*max1);
            max1=max(max1,a[j]);
        }
    }
    printf("%d",f[n]);
    return 0;
}
